.nge-notif-topbar[data-v-cf825e08] {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  flex-shrink: 0;
}
.nge-notif-title[data-v-cf825e08] {
  font-size: 1em;
  font-weight: 600;
  color: #e0e0e0;
}
.nge-notif-topbar-actions[data-v-cf825e08] { display: flex; align-items: center; gap: 8px;
}
.nge-notif-mark-all[data-v-cf825e08] {
  background: none;
  border: 1px solid rgba(74, 158, 255, 0.2);
  color: rgba(74, 158, 255, 0.7);
  font-size: 0.72em;
  padding: 2px 8px;
  border-radius: 8px;
