.nge-notif-mark-all[data-v-cf825e08]:hover { color: #4a9eff; border-color: rgba(74, 158, 255, 0.4);
}
.nge-notif-close[data-v-cf825e08] {
  background: none; border: none; color: #666; font-size: 1.2em;
  cursor: pointer; padding: 0 4px;
}
.nge-notif-close[data-v-cf825e08]:hover { color: #fff;
}
.nge-notif-list[data-v-cf825e08] {
  overflow-y: auto;
  max-height: 420px;
  padding: 6px 0;
