/* ── Feed cards (compact list) ── */
.nge-notif-card[data-v-cf825e08] {
  padding: 10px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
  cursor: pointer;
  transition: background 0.15s;
}
.nge-notif-card[data-v-cf825e08]:hover { background: rgba(74, 158, 255, 0.04);
}
.nge-notif-card--unread[data-v-cf825e08] { background: rgba(74, 158, 255, 0.03);
}
.nge-notif-card-row[data-v-cf825e08] {
  display: flex;
  gap: 10px;
  align-items: flex-start;
}
.nge-notif-card-content[data-v-cf825e08] {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.nge-notif-thumb-sm[data-v-cf825e08] {
  width: 40px;
  height: 40px;
  object-fit: cover;
  border-radius: 6px;
  flex-shrink: 0;
  opacity: 0.85;
  margin-top: 2px;
}
.nge-notif-thumb-fallback[data-v-cf825e08] {
  opacity: 0.35;
  padding: 6px;
  background: rgba(74, 158, 255, 0.06);
  border-radius: 8px;
}
.nge-notif-unread-dot[data-v-cf825e08] {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #4a9eff;
  flex-shrink: 0;
  margin-top: 4px;
}
.nge-notif-card-header[data-v-cf825e08] {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 8px;
}
.nge-notif-card-title[data-v-cf825e08] {
  font-weight: 600;
  color: #dde;
  font-size: 0.92em;
  flex: 1;
}
.nge-notif-time[data-v-cf825e08] {
  font-size: 0.72em;
  color: #556;
  flex-shrink: 0;
}
.nge-notif-delete[data-v-cf825e08] {
  background: none;
  border: none;
  font-size: 0.7em;
  cursor: pointer;
  opacity: 0;
  padding: 0 2px;
  transition: opacity 0.15s;
  flex-shrink: 0;
  filter: grayscale(1);
}
.nge-notif-card:hover .nge-notif-delete[data-v-cf825e08] { opacity: 0.5;
}
.nge-notif-delete[data-v-cf825e08]:hover { opacity: 1 !important; filter: none;
}
.nge-notif-dismiss[data-v-cf825e08] {
  background: none;
  border: none;
  font-size: 1.1em;
  color: #556;
  cursor: pointer;
  opacity: 0.45;
  padding: 2px 4px;
  transition: opacity 0.15s, color 0.15s;
  flex-shrink: 0;
  line-height: 1;
}
.nge-notif-dismiss[data-v-cf825e08]:hover { opacity: 1; color: #f66;
}
.nge-notif-card-body[data-v-cf825e08] {
  font-size: 0.82em;
  color: #888;
  line-height: 1.4;
}
.nge-notif-card-body--preview[data-v-cf825e08] {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.nge-notif-empty[data-v-cf825e08] {
  padding: 32px 16px;
  text-align: center;
  color: #556;
  font-size: 0.82em;
  font-style: italic;
}

/* ═══ Detail overlay ═══ */
.nge-notif-detail-backdrop[data-v-cf825e08] {
  position: fixed;
  inset: 0;
  z-index: 9500;
  background: rgba(0, 0, 0, 0.6);
  display: flex;
  align-items: center;
  justify-content: center;
}
.nge-notif-detail[data-v-cf825e08] {
  width: 740px;
  max-width: 90vw;
  max-height: 80vh;
  background: linear-gradient(135deg, rgba(4, 6, 14, 0.97) 0%, rgba(8, 12, 24, 0.95) 50%, rgba(4, 8, 18, 0.97) 100%);
  border: 1px solid rgba(74, 158, 255, 0.2);
  border-radius: 12px;
  box-shadow: 0 16px 64px rgba(0, 0, 0, 0.7), 0 0 40px rgba(74, 158, 255, 0.06);
  display: flex;
  flex-direction: column;
  backdrop-filter: blur(12px);
  font-family: sans-serif;
}
.nge-notif-detail-topbar[data-v-cf825e08] {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 18px 10px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  flex-shrink: 0;
}
.nge-notif-detail-time[data-v-cf825e08] {
  font-size: 0.75em;
  color: #556;
}
.nge-notif-detail-close[data-v-cf825e08] {
  background: none;
  border: none;
  color: #666;
  font-size: 1.4em;
  cursor: pointer;
  padding: 0 4px;
  line-height: 1;
}
.nge-notif-detail-close[data-v-cf825e08]:hover { color: #fff;
}
.nge-notif-detail-scroll[data-v-cf825e08] {
  overflow-y: auto;
  padding: 18px 22px 24px;
  scrollbar-width: thin;
  scrollbar-color: rgba(74, 158, 255, 0.15) transparent;
}
.nge-notif-detail-title[data-v-cf825e08] {
  font-size: 1.2em;
  font-weight: 700;
  color: #e8e8ee;
  margin: 0 0 14px;
  line-height: 1.3;
}
.nge-notif-detail-body[data-v-cf825e08] {
  font-size: 0.95em;
  color: #b0b0b8;
  line-height: 1.65;
  white-space: pre-wrap;
  word-break: break-word;
}
.nge-notif-detail-body[data-v-cf825e08] .nge-notif-link {
  color: #4a9eff;
  text-decoration: none;
  word-break: break-all;
}
.nge-notif-detail-body[data-v-cf825e08] .nge-notif-link:hover {
  text-decoration: underline;
}
.nge-notif-detail-layout[data-v-cf825e08] {
  display: flex;
  flex-direction: column;
}
.nge-notif-detail-layout--has-image[data-v-cf825e08] {
  flex-direction: row;
  gap: 18px;
}
.nge-notif-detail-image[data-v-cf825e08] {
  flex-shrink: 0;
}
.nge-notif-detail-layout--has-image .nge-notif-detail-image[data-v-cf825e08] {
  width: 320px;
}
.nge-notif-detail-text[data-v-cf825e08] {
  flex: 1;
  min-width: 0;
}
.nge-notif-detail-img[data-v-cf825e08] {
  width: 100%;
  max-height: 600px;
  border-radius: 8px;
  object-fit: contain;
  cursor: zoom-in;
}

/* Help notification action */
.nge-notif-open-help[data-v-cf825e08] {
  margin-top: 14px;
  padding: 7px 16px;
  border: 1px solid rgba(255, 136, 170, 0.25);
  border-radius: 6px;
  background: rgba(255, 136, 170, 0.08);
  color: #f8a;
  font-size: 0.85em;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.15s;
}
.nge-notif-open-help[data-v-cf825e08]:hover {
  background: rgba(255, 136, 170, 0.15);
  border-color: rgba(255, 136, 170, 0.4);
}

/* ── Transition ── */
.nge-notif-detail-enter-active[data-v-cf825e08] { transition: opacity 0.2s ease;
}
.nge-notif-detail-enter-active .nge-notif-detail[data-v-cf825e08] { transition: transform 0.2s ease, opacity 0.2s ease;
}
.nge-notif-detail-leave-active[data-v-cf825e08] { transition: opacity 0.15s ease;
}
.nge-notif-detail-leave-active .nge-notif-detail[data-v-cf825e08] { transition: transform 0.15s ease, opacity 0.15s ease;
}
.nge-notif-detail-enter-from[data-v-cf825e08] { opacity: 0;
}
.nge-notif-detail-enter-from .nge-notif-detail[data-v-cf825e08] { transform: scale(0.95) translateY(8px); opacity: 0;
}
.nge-notif-detail-leave-to[data-v-cf825e08] { opacity: 0;
}
.nge-notif-detail-leave-to .nge-notif-detail[data-v-cf825e08] { transform: scale(0.97); opacity: 0;
}

/* ── Lightbox ── */
.nge-notif-lightbox[data-v-cf825e08] {
  position: fixed;
  inset: 0;
  z-index: 10001;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
}
.nge-notif-lightbox-img[data-v-cf825e08] {
  max-width: 90vw;
  max-height: 90vh;
  object-fit: contain;
  border-radius: 8px;
}
