
.nge-bp-panel[data-v-6de8c668] {
  position: fixed;
  z-index: 10010;
  width: 420px;
  max-height: 75vh;
  display: flex;
  flex-direction: column;
  background: #1a1a2e;
  border: 1px solid rgba(120, 140, 255, 0.15);
  border-radius: 14px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
  font-family: 'SF Mono', ui-monospace, 'Cascadia Code', 'Fira Code', monospace;
  color: #ccd;
  overflow: hidden;
}
.nge-bp-enter-active[data-v-6de8c668], .nge-bp-leave-active[data-v-6de8c668] { transition: opacity 0.2s, transform 0.2s;
}
.nge-bp-enter-from[data-v-6de8c668], .nge-bp-leave-to[data-v-6de8c668] { opacity: 0; transform: translateY(10px) scale(0.97);
}

/* Top bar */
.nge-bp-topbar[data-v-6de8c668] {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 14px;
  background: rgba(30, 30, 60, 0.9);
  cursor: grab;
  user-select: none;
  border-bottom: 1px solid rgba(120, 140, 255, 0.08);
}
.nge-bp-dragging[data-v-6de8c668] { cursor: grabbing;
}
.nge-bp-title[data-v-6de8c668] { font-size: 0.9em; font-weight: 700; letter-spacing: 0.03em; color: #eef;
}
.nge-bp-close[data-v-6de8c668] { background: none; border: none; color: #889; font-size: 1.4em; cursor: pointer; padding: 0 4px; line-height: 1;
}
.nge-bp-close[data-v-6de8c668]:hover { color: #eef;
}

/* Flash message */
.nge-bp-flash[data-v-6de8c668] {
