}
.nge-bp-flash-leave-active[data-v-6de8c668] { transition: opacity 0.3s;
}
.nge-bp-flash-enter-from[data-v-6de8c668], .nge-bp-flash-leave-to[data-v-6de8c668] { opacity: 0;
