  border-bottom: 1px solid rgba(120, 140, 255, 0.06);
}

/* Inputs */
.nge-bp-input[data-v-6de8c668] {
  padding: 5px 8px;
  border: 1px solid rgba(120, 140, 255, 0.12);
  border-radius: 5px;
