}
.nge-bp-input--flex[data-v-6de8c668] { flex: 1; min-width: 0;
}
.nge-bp-create .nge-bp-input[data-v-6de8c668] { flex: 1;
}

/* Buttons */
.nge-bp-btn[data-v-6de8c668] {
  padding: 4px 10px;
  border: 1px solid rgba(120, 140, 255, 0.15);
  border-radius: 5px;
  background: transparent;
  color: #8bf;
  font-size: 0.72em;
