  overflow-y: auto;
  padding: 4px 0;
}
.nge-bp-list[data-v-6de8c668]::-webkit-scrollbar { width: 4px;
}
.nge-bp-list[data-v-6de8c668]::-webkit-scrollbar-thumb { background: rgba(120, 140, 255, 0.15); border-radius: 2px;
}
.nge-bp-group[data-v-6de8c668] {
  border-bottom: 1px solid rgba(120, 140, 255, 0.04);
}

