  background: rgba(10, 10, 30, 0.3);
}
.nge-bp-rename[data-v-6de8c668] {
  margin-bottom: 6px;
}
.nge-bp-rename .nge-bp-input[data-v-6de8c668] { width: 100%;
}

/* Chips */
.nge-bp-chips[data-v-6de8c668] {
  display: flex;
  flex-wrap: wrap;
  gap: 3px;
  margin-bottom: 6px;
  max-height: 120px;
  overflow-y: auto;
}
.nge-bp-chip[data-v-6de8c668] {
