.nge-bp-act[data-v-6de8c668]:hover:not(:disabled) { background: rgba(120, 140, 255, 0.06); color: #bbf;
}
.nge-bp-act[data-v-6de8c668]:disabled { opacity: 0.3; cursor: default;
}
.nge-bp-act--color[data-v-6de8c668]:hover:not(:disabled) { border-color: rgba(255, 170, 68, 0.3); color: #fa4;
