.nge-bp-act--complete[data-v-6de8c668]:hover:not(:disabled) { border-color: rgba(68, 170, 255, 0.3); color: #4af;
}
.nge-bp-act--annotate[data-v-6de8c668]:hover:not(:disabled) { border-color: rgba(206, 147, 216, 0.3); color: #CE93D8;
}
.nge-bp-act--copy[data-v-6de8c668]:hover:not(:disabled) { border-color: rgba(68, 170, 102, 0.3); color: #4a6;
}
.nge-bp-act--remove[data-v-6de8c668]:hover:not(:disabled) { border-color: rgba(255, 100, 100, 0.3); color: #f66;
