/* ── Particles (40, multi-layered) ── */
.nge-hero-particles[data-v-bcd5f0a5] { position: absolute; inset: -40px; pointer-events: none; overflow: visible; z-index: 0;
}
.nge-hero-particle[data-v-bcd5f0a5] {
