.nge-toast--quest .nge-toast-progress[data-v-bcd5f0a5]  { background: rgba(0, 200, 255, 0.4);
}
@keyframes nge-toast-countdown-bcd5f0a5 {
from { width: 100%;
}
to   { width: 0%;
}
}

/* ── Sparkle particles ── */
.nge-toast-particles[data-v-bcd5f0a5] {
  position: absolute;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
}
.nge-toast-particle[data-v-bcd5f0a5] {
  position: absolute;
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: rgba(200, 220, 255, 0.6);
  animation: nge-toast-sparkle-bcd5f0a5 1.2s ease-out forwards;
  animation-delay: calc(var(--i) * 0.08s);
  left: calc(10% + var(--i) * 14%);
  top: 50%;
}
.nge-toast--badge .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(206, 147, 216, 0.7);
}
.nge-toast--streak .nge-toast-particle[data-v-bcd5f0a5] { background: rgba(245, 166, 35, 0.7);
}
.nge-toast--cells .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(129, 199, 132, 0.7);
}
.nge-toast--quest .nge-toast-particle[data-v-bcd5f0a5]  { background: rgba(0, 200, 255, 0.7);
}
@keyframes nge-toast-sparkle-bcd5f0a5 {
0%   { opacity: 1; transform: translate(0, 0) scale(1);
}
50%  { opacity: 0.8; transform: translate(calc((var(--i) - 3) * 8px), -20px) scale(0.6);
}
100% { opacity: 0; transform: translate(calc((var(--i) - 3) * 14px), -35px) scale(0);
}
}

/* ── Transitions ── */
.nge-toast-enter-active[data-v-bcd5f0a5] {
  transition: all 0.35s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.nge-toast-leave-active[data-v-bcd5f0a5] {
  transition: all 0.25s ease-in;
}
.nge-toast-enter-from[data-v-bcd5f0a5] {
  opacity: 0;
  transform: translateX(100px) scale(0.8);
}
.nge-toast-leave-to[data-v-bcd5f0a5] {
  opacity: 0;
  transform: translateX(60px) scale(0.9);
}
.nge-toast-move[data-v-bcd5f0a5] {
  transition: transform 0.3s ease;
}
