
/* ══════════════════════════════════════════════════════════════════════════
   HOLOGRAPHIC SCI-FI LOGIN MODAL
   ══════════════════════════════════════════════════════════════════════════ */
.nge-login-blocker[data-v-d1dbaecf] {
  position: fixed;
  inset: 0;
  z-index: 10000;
  background: radial-gradient(ellipse at center, rgba(0, 15, 40, 0.85) 0%, rgba(0, 0, 0, 0.95) 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(12px) saturate(1.3);
  font-family: 'Inter', 'Segoe UI', system-ui, -apple-system, sans-serif;
}

/* ── Floating particle grid ── */
.nge-holo-particles[data-v-d1dbaecf] {
  position: absolute;
  inset: 0;
  background-image:
    radial-gradient(1px 1px at 20% 30%, rgba(74, 158, 255, 0.3) 0%, transparent 100%),
    radial-gradient(1px 1px at 40% 70%, rgba(0, 210, 255, 0.2) 0%, transparent 100%),
    radial-gradient(1px 1px at 80% 40%, rgba(206, 147, 216, 0.2) 0%, transparent 100%),
    radial-gradient(1.5px 1.5px at 65% 80%, rgba(74, 158, 255, 0.25) 0%, transparent 100%),
    radial-gradient(1px 1px at 90% 15%, rgba(0, 255, 200, 0.15) 0%, transparent 100%),
    radial-gradient(1px 1px at 10% 85%, rgba(74, 158, 255, 0.2) 0%, transparent 100%);
  background-size: 250px 250px, 300px 300px, 200px 200px, 350px 350px, 180px 180px, 280px 280px;
  animation: nge-holo-drift-d1dbaecf 20s linear infinite;
  pointer-events: none;
  opacity: 0.6;
}
@keyframes nge-holo-drift-d1dbaecf {
0%   { transform: translate(0, 0);
}
100% { transform: translate(-60px, -40px);
}
}

/* ── Main modal ── */
.nge-login-modal[data-v-d1dbaecf] {
  background:
    linear-gradient(165deg,
      rgba(10, 18, 35, 0.95) 0%,
      rgba(5, 10, 22, 0.98) 100%);
  border: 1px solid rgba(0, 180, 255, 0.18);
  border-radius: 2px;
  padding: 44px 48px 32px;
  text-align: center;
  max-width: 460px;
  width: 90%;
  position: relative;
  overflow: hidden;
  animation: nge-holo-materialize-d1dbaecf 0.8s cubic-bezier(0.16, 1, 0.3, 1) both;
  box-shadow:
    0 0 80px rgba(0, 150, 255, 0.08),
    0 0 200px rgba(0, 150, 255, 0.03),
    inset 0 0 80px rgba(0, 100, 200, 0.02),
    0 20px 60px rgba(0, 0, 0, 0.5);
}

/* Outer glow border effect */
.nge-login-modal[data-v-d1dbaecf]::before {
  content: '';
  position: absolute;
  inset: -1px;
  border-radius: 2px;
  background: linear-gradient(
    135deg,
    rgba(0, 180, 255, 0.4) 0%,
    rgba(0, 100, 200, 0.05) 25%,
    rgba(120, 0, 255, 0.15) 50%,
    rgba(0, 100, 200, 0.05) 75%,
    rgba(0, 220, 180, 0.3) 100%
  );
  background-size: 300% 300%;
  animation: nge-holo-border-d1dbaecf 6s ease-in-out infinite;
  z-index: -1;
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask-composite: exclude;
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  padding: 1px;
}

/* Inner ambient glow */
.nge-login-modal[data-v-d1dbaecf]::after {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(
    ellipse at 50% 0%,
    rgba(0, 150, 255, 0.06) 0%,
    transparent 60%
  );
  pointer-events: none;
}
@keyframes nge-holo-materialize-d1dbaecf {
0%   {
    opacity: 0;
    transform: scale(1.04) translateY(-10px);
    filter: blur(20px) brightness(3);
    box-shadow: 0 0 120px rgba(0, 180, 255, 0.5);
}
30%  {
    opacity: 0.6;
    filter: blur(3px) brightness(1.5);
}
60%  {
    opacity: 1;
    transform: scale(0.99);
    filter: blur(0) brightness(1.1);
}
100% {
    opacity: 1;
    transform: scale(1) translateY(0);
    filter: blur(0) brightness(1);
}
}
@keyframes nge-holo-border-d1dbaecf {
0%   { background-position: 0% 50%;
}
50%  { background-position: 100% 50%;
}
100% { background-position: 0% 50%;
}
}

/* ── Glowing ring around icon ── */
.nge-holo-ring-container[data-v-d1dbaecf] {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 130px;
  height: 130px;
  margin-bottom: 14px;
}
.nge-holo-ring[data-v-d1dbaecf] {
  position: absolute;
  inset: 0;
  border: 1.5px solid rgba(0, 180, 255, 0.25);
  border-radius: 50%;
  border-top-color: rgba(0, 220, 255, 0.8);
  border-right-color: rgba(120, 0, 255, 0.4);
  animation: nge-holo-spin-d1dbaecf 3s linear infinite;
}
.nge-holo-ring--inner[data-v-d1dbaecf] {
  inset: 10px;
  border-color: rgba(0, 150, 255, 0.1);
  border-bottom-color: rgba(0, 255, 200, 0.5);
  border-left-color: rgba(0, 200, 255, 0.3);
  animation-duration: 5s;
  animation-direction: reverse;
}
@keyframes nge-holo-spin-d1dbaecf {
from { transform: rotate(0deg);
}
to   { transform: rotate(360deg);
}
}
.nge-login-icon[data-v-d1dbaecf] {
  position: relative;
  z-index: 2;
  width: 90px;
  height: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
  filter: drop-shadow(0 0 18px rgba(0, 180, 255, 0.5));
  animation: nge-holo-icon-breathe-d1dbaecf 3s ease-in-out infinite;
}
.nge-neuron-svg[data-v-d1dbaecf] {
  width: 90px;
  height: 100px;
}
@keyframes nge-holo-icon-breathe-d1dbaecf {
0%, 100% { filter: drop-shadow(0 0 12px rgba(0, 180, 255, 0.4));
}
50%      { filter: drop-shadow(0 0 24px rgba(0, 200, 255, 0.7));
}
}

/* ── Eyebrow label ── */
.nge-holo-eyebrow[data-v-d1dbaecf] {
  font-size: 0.58em;
  font-weight: 700;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: rgba(0, 200, 255, 0.5);
  margin-bottom: 6px;
  position: relative;
  z-index: 2;
}
.nge-login-title[data-v-d1dbaecf] {
  font-size: 1.5em;
  font-weight: 300;
  color: rgba(200, 230, 255, 0.95);
  margin-bottom: 8px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  position: relative;
  z-index: 2;
  text-shadow: 0 0 30px rgba(0, 150, 255, 0.3);
}
.nge-login-desc[data-v-d1dbaecf] {
  font-size: 0.78em;
  color: rgba(120, 160, 200, 0.6);
  line-height: 1.6;
  margin-bottom: 24px;
  letter-spacing: 0.02em;
  position: relative;
  z-index: 2;
}

/* ── Server list ── */
.nge-login-servers[data-v-d1dbaecf] {
  margin-bottom: 24px;
  text-align: left;
  position: relative;
  z-index: 2;
}
.nge-login-server-row[data-v-d1dbaecf] {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 1px;
  background: rgba(0, 120, 255, 0.04);
  border: 1px solid rgba(0, 180, 255, 0.1);
  border-left: 2px solid rgba(0, 200, 255, 0.3);
  margin-bottom: 6px;
  transition: all 0.3s;
}
.nge-login-server-row--done[data-v-d1dbaecf] {
  border-left-color: rgba(0, 255, 150, 0.5);
  background: rgba(0, 255, 150, 0.03);
  border-color: rgba(0, 255, 150, 0.1);
  border-left-color: rgba(0, 255, 150, 0.5);
}
.nge-login-server-row--waiting[data-v-d1dbaecf] {
  border-left-color: rgba(0, 200, 255, 0.6);
  animation: nge-holo-row-pulse-d1dbaecf 1.5s ease-in-out infinite;
}
@keyframes nge-holo-row-pulse-d1dbaecf {
0%, 100% { background: rgba(0, 120, 255, 0.04);
}
50%      { background: rgba(0, 150, 255, 0.08);
}
}
.nge-login-server-status[data-v-d1dbaecf] {
  flex-shrink: 0;
  width: 22px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.nge-holo-check[data-v-d1dbaecf] {
  color: rgba(0, 255, 150, 0.9);
  font-weight: 700;
  font-size: 0.9em;
  text-shadow: 0 0 8px rgba(0, 255, 150, 0.5);
}
.nge-holo-dot[data-v-d1dbaecf] {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: rgba(0, 180, 255, 0.3);
  border: 1px solid rgba(0, 200, 255, 0.5);
  box-shadow: 0 0 6px rgba(0, 200, 255, 0.3);
}
.nge-holo-spinner[data-v-d1dbaecf] {
  width: 14px;
  height: 14px;
  border: 1.5px solid rgba(0, 180, 255, 0.15);
  border-top-color: rgba(0, 220, 255, 0.9);
  border-radius: 50%;
  animation: nge-holo-spin-d1dbaecf 0.8s linear infinite;
}
.nge-login-server-url[data-v-d1dbaecf] {
  flex: 1;
  font-size: 0.78em;
  font-family: 'SF Mono', ui-monospace, 'Cascadia Code', monospace;
  color: rgba(0, 180, 255, 0.6);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  letter-spacing: 0.03em;
}
.nge-login-server-btn[data-v-d1dbaecf] {
  flex-shrink: 0;
  padding: 5px 16px;
  border: 1px solid rgba(0, 200, 255, 0.3);
  border-radius: 1px;
  background: rgba(0, 150, 255, 0.08);
  color: rgba(0, 220, 255, 0.9);
  font-size: 0.68em;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  transition: all 0.2s;
}
.nge-login-server-btn[data-v-d1dbaecf]:hover:not(:disabled) {
  background: rgba(0, 180, 255, 0.18);
  border-color: rgba(0, 220, 255, 0.6);
  box-shadow: 0 0 16px rgba(0, 200, 255, 0.2);
}
.nge-login-server-btn[data-v-d1dbaecf]:disabled {
  opacity: 0.5;
  cursor: wait;
}
.nge-login-server-ok[data-v-d1dbaecf] {
  flex-shrink: 0;
  font-size: 0.68em;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: rgba(0, 255, 150, 0.8);
  text-shadow: 0 0 10px rgba(0, 255, 150, 0.3);
}

/* ── Main CTA button ── */
.nge-login-btn[data-v-d1dbaecf] {
  display: block;
  width: 100%;
  padding: 14px 24px;
  border: 1px solid rgba(0, 180, 255, 0.3);
  border-radius: 2px;
  background: linear-gradient(135deg,
    rgba(0, 100, 255, 0.2) 0%,
    rgba(0, 60, 180, 0.3) 50%,
    rgba(80, 0, 200, 0.2) 100%
  );
  color: rgba(200, 230, 255, 0.95);
  font-size: 0.88em;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  transition: all 0.3s;
  position: relative;
  z-index: 2;
  overflow: hidden;
}
.nge-login-btn-text[data-v-d1dbaecf] {
  position: relative;
  z-index: 2;
}
.nge-login-btn-glow[data-v-d1dbaecf] {
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg,
    transparent 0%,
    rgba(0, 200, 255, 0.15) 50%,
    transparent 100%
  );
  animation: nge-holo-btn-sweep-d1dbaecf 3s ease-in-out infinite;
  pointer-events: none;
}
@keyframes nge-holo-btn-sweep-d1dbaecf {
0%   { transform: translateX(-100%);
}
100% { transform: translateX(100%);
}
}
.nge-login-btn[data-v-d1dbaecf]:hover:not(:disabled) {
  border-color: rgba(0, 220, 255, 0.6);
  background: linear-gradient(135deg,
    rgba(0, 120, 255, 0.3) 0%,
    rgba(0, 80, 200, 0.4) 50%,
    rgba(100, 0, 255, 0.25) 100%
  );
  box-shadow:
    0 0 30px rgba(0, 180, 255, 0.15),
    inset 0 0 30px rgba(0, 150, 255, 0.05);
  transform: translateY(-1px);
}
.nge-login-btn[data-v-d1dbaecf]:active:not(:disabled) {
  transform: translateY(0);
  box-shadow: 0 0 40px rgba(0, 200, 255, 0.25);
}
.nge-login-btn[data-v-d1dbaecf]:disabled {
  opacity: 0.4;
  cursor: default;
}

/* ── Skip/bypass ── */
.nge-login-skip[data-v-d1dbaecf] {
  display: block;
  width: 100%;
  margin-top: 14px;
  padding: 8px;
  background: none;
  border: none;
  color: rgba(100, 140, 180, 0.35);
  font-size: 0.65em;
  font-weight: 700;
  font-family: inherit;
  cursor: pointer;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  transition: color 0.15s;
  position: relative;
  z-index: 2;
}
.nge-login-skip[data-v-d1dbaecf]:hover {
  color: rgba(0, 200, 255, 0.5);
}

/* ── Bottom data stream text ── */
.nge-holo-datastream[data-v-d1dbaecf] {
  margin-top: 20px;
  font-size: 0.5em;
  font-family: 'SF Mono', ui-monospace, 'Cascadia Code', monospace;
  color: rgba(0, 180, 255, 0.2);
  letter-spacing: 0.08em;
  position: relative;
  z-index: 2;
  animation: nge-holo-flicker-d1dbaecf 8s ease-in-out infinite;
}
@keyframes nge-holo-flicker-d1dbaecf {
0%, 100% { opacity: 1;
}
92%      { opacity: 1;
}
93%      { opacity: 0.3;
}
94%      { opacity: 1;
}
96%      { opacity: 0.6;
}
97%      { opacity: 1;
}
}

/* ── Transition ── */
.nge-login-modal-enter-active[data-v-d1dbaecf] { transition: all 0.4s ease-out;
}
.nge-login-modal-leave-active[data-v-d1dbaecf] { transition: all 0.25s ease-in;
}
.nge-login-modal-enter-from[data-v-d1dbaecf]   { opacity: 0;
}
.nge-login-modal-leave-to[data-v-d1dbaecf]     { opacity: 0; filter: blur(8px) brightness(2);
}
